// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.4;

// interfaces
import {
    IERC725Y
} from "@erc725/smart-contracts/contracts/interfaces/IERC725Y.sol";

// libraries
import {LSP2Utils} from "../LSP2ERC725YJSONSchema/LSP2Utils.sol";

// constants
import {_INTERFACEID_LSP9} from "../LSP9Vault/LSP9Constants.sol";
import {
    _LSP10_VAULTS_MAP_KEY_PREFIX,
    _LSP10_VAULTS_ARRAY_KEY
} from "../LSP10ReceivedVaults/LSP10Constants.sol";

/**
 * @title LSP10 Utility library.
 * @author Yamen Merhi <YamenMerhi>, Jean Cavallera <CJ42>
 * @dev LSP5Utils is a library of functions that can be used to register and manage vaults received by an ERC725Y smart contract.
 * Based on the LSP10 Received Vaults standard.
 */
library LSP10Utils {
    /**
     * @dev Generate an array of data keys/values pairs to be set on the receiver address after receiving vaults.
     *
     * @custom:warning This function returns empty arrays when encountering errors. Otherwise the arrays will contain 3 data keys and 3 data values.
     *
     * @param receiver The address receiving the vault and where the LSP10 data keys should be added.
     * @param vaultAddress The address of the vault being received.
     *
     * @return lsp10DataKeys An array data keys used to update the [LSP-10-ReceivedAssets] data.
     * @return lsp10DataValues An array data values used to update the [LSP-10-ReceivedAssets] data.
     */
    function generateReceivedVaultKeys(
        address receiver,
        address vaultAddress
    )
        internal
        view
        returns (bytes32[] memory lsp10DataKeys, bytes[] memory lsp10DataValues)
    {
        IERC725Y erc725YContract = IERC725Y(receiver);

        /// --- `LSP10Vaults[]` Array ---

        bytes memory currentArrayLengthBytes = getLSP10ArrayLengthBytes(
            erc725YContract
        );

        // CHECK that the value of `LSP10Vaults[]` Array length is a valid `uint128` (16 bytes long)
        if (!LSP2Utils.isValidLSP2ArrayLengthValue(currentArrayLengthBytes)) {
            if (currentArrayLengthBytes.length == 0) {
                // if it's the first vault received and nothing is set (= 0x)
                // we need to convert it to: `0x00000000000000000000000000000000`
                // to safely cast to a uint128 of length 0
                currentArrayLengthBytes = abi.encodePacked(bytes16(0));
            } else {
                // otherwise the array length is invalid
                return (lsp10DataKeys, lsp10DataValues);
            }
        }

        uint128 currentArrayLength = uint128(bytes16(currentArrayLengthBytes));

        // CHECK for potential overflow
        if (currentArrayLength == type(uint128).max) {
            return (lsp10DataKeys, lsp10DataValues);
        }

        // --- `LSP10VaultsMap:<vaultAddress>` ---

        bytes32 mapDataKey = LSP2Utils.generateMappingKey(
            _LSP10_VAULTS_MAP_KEY_PREFIX,
            bytes20(vaultAddress)
        );

        // CHECK that the map value is not already set in the storage for the newly received vault
        // If that's the case, the vault is already registered. Do not try to update.
        if (erc725YContract.getData(mapDataKey).length != 0) {
            return (lsp10DataKeys, lsp10DataValues);
        }

        /// --- LSP10 Data Keys & Values ---

        lsp10DataKeys = new bytes32[](3);
        lsp10DataValues = new bytes[](3);

        // Increment `LSP10Vaults[]` Array length
        lsp10DataKeys[0] = _LSP10_VAULTS_ARRAY_KEY;
        lsp10DataValues[0] = abi.encodePacked(currentArrayLength + 1);

        // Add asset address to `LSP10Vaults[index]`, where index == previous array length
        lsp10DataKeys[1] = LSP2Utils.generateArrayElementKeyAtIndex(
            _LSP10_VAULTS_ARRAY_KEY,
            currentArrayLength
        );
        lsp10DataValues[1] = abi.encodePacked(vaultAddress);

        // Add interfaceId + index as value under `LSP10VaultsMap:<vaultAddress>`
        lsp10DataKeys[2] = mapDataKey;
        lsp10DataValues[2] = bytes.concat(
            _INTERFACEID_LSP9,
            currentArrayLengthBytes
        );
    }

    /**
     * @dev Generate an array of data key/value pairs to be set on the sender address after sending vaults.
     *
     * @custom:warning Returns empty arrays when encountering errors. Otherwise the arrays must have at least 3 data keys and 3 data values.
     *
     * @param sender The address sending the vault and where the LSP10 data keys should be updated.
     * @param vaultAddress The address of the vault that is being sent.
     *
     * @return lsp10DataKeys An array data keys used to update the [LSP-10-ReceivedAssets] data.
     * @return lsp10DataValues An array data values used to update the [LSP-10-ReceivedAssets] data.
     */
    function generateSentVaultKeys(
        address sender,
        address vaultAddress
    )
        internal
        view
        returns (bytes32[] memory lsp10DataKeys, bytes[] memory lsp10DataValues)
    {
        IERC725Y erc725YContract = IERC725Y(sender);

        // --- `LSP10Vaults[]` Array ---

        bytes memory newArrayLengthBytes = getLSP10ArrayLengthBytes(
            erc725YContract
        );

        // CHECK that the value of `LSP10Vaults[]` Array length is a valid `uint128` (16 bytes long)
        if (!LSP2Utils.isValidLSP2ArrayLengthValue(newArrayLengthBytes)) {
            return (lsp10DataKeys, lsp10DataValues);
        }

        // CHECK for potential underflow
        if (
            newArrayLengthBytes.length == 0 ||
            bytes16(newArrayLengthBytes) == bytes16(0)
        ) {
            return (lsp10DataKeys, lsp10DataValues);
        }

        uint128 newArrayLength = uint128(bytes16(newArrayLengthBytes)) - 1;

        // --- `LSP10VaultssMap:<vaultAddress>` ---

        bytes32 removedElementMapKey = LSP2Utils.generateMappingKey(
            _LSP10_VAULTS_MAP_KEY_PREFIX,
            bytes20(vaultAddress)
        );

        // Query the ERC725Y storage of the LSP0-ERC725Account
        bytes memory mapValue = erc725YContract.getData(removedElementMapKey);

        // CHECK if no map value was set for the vault to remove.
        // If that's the case, there is nothing to remove. Do not try to update.
        if (mapValue.length != 20) {
            return (lsp10DataKeys, lsp10DataValues);
        }

        // Extract index of vault to remove from the map value
        uint128 removedElementIndex = uint128(bytes16(bytes20(mapValue) << 32));

        bytes32 removedElementIndexKey = LSP2Utils
            .generateArrayElementKeyAtIndex(
                _LSP10_VAULTS_ARRAY_KEY,
                uint128(removedElementIndex)
            );

        if (removedElementIndex == newArrayLength) {
            return
                LSP2Utils.removeLastElementFromArrayAndMap(
                    _LSP10_VAULTS_ARRAY_KEY,
                    newArrayLength,
                    removedElementIndexKey,
                    removedElementMapKey
                );
        } else if (removedElementIndex < newArrayLength) {
            return
                LSP2Utils.removeElementFromArrayAndMap(
                    erc725YContract,
                    _LSP10_VAULTS_ARRAY_KEY,
                    newArrayLength,
                    removedElementIndexKey,
                    removedElementIndex,
                    removedElementMapKey
                );
        } else {
            // If index is bigger than the array length, out of bounds
            return (lsp10DataKeys, lsp10DataValues);
        }
    }

    /**
     * @dev Get the raw bytes value stored under the `_LSP10_VAULTS_ARRAY_KEY`.
     * @param erc725YContract The contract to query the ERC725Y storage from.
     * @return The raw bytes value stored under this data key.
     */
    function getLSP10ArrayLengthBytes(
        IERC725Y erc725YContract
    ) internal view returns (bytes memory) {
        return erc725YContract.getData(_LSP10_VAULTS_ARRAY_KEY);
    }
}

contracts/LSP11BasicSocialRecovery/ILSP1.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.0;

/**
 * @title Interface of the LSP11 - Basic Social Recovery standard, a contract to recover access control into an account.
 * @dev Sets permission for a controller address after a recovery process to interact with an ERC725
 * contract via the LSP6KeyManager
 */
interface ILSP11BasicSocialRecovery {
    /**
     * @notice Emitted when setting a new guardian for the target
     * @param newGuardian The address of the added guardian
     */
    event GuardianAdded(address indexed newGuardian);

    /**
     * @notice Emitted when removing an existing guardian for the target
     * @param removedGuardian The address of the guardian removed
     */
    event GuardianRemoved(address indexed removedGuardian);

    /**
     * @notice Emitted when changing the guardian threshold
     * @param guardianThreshold The minimum number of selection by guardians needed by a controller to start
     * a recovery process
     */
    event GuardiansThresholdChanged(uint256 indexed guardianThreshold);

    /**
     * @notice Emitted when changing the secret hash
     * @param secretHash The secret hash used to finish the recovery process
     */
    event SecretHashChanged(bytes32 indexed secretHash);

    /**
     * @notice Emitted when a guardian select a new potentiel controller address for the target
     * @param recoveryCounter The current recovery process counter
     * @param guardian The address of the guardian
     * @param addressSelected The address selected by the guardian
     */
    event SelectedNewController(
        uint256 indexed recoveryCounter,
        address indexed guardian,
        address indexed addressSelected
    );

    /**
     * @notice Emitted when the recovery process is finished by the controller who
     * reached the guardian threshold and submitted the string that produce the secretHash
     * @param recoveryCounter The current recovery process
     * @param newController The address of the new controller controlling the target by the KeyManager
     * @param guardians The array of addresses containing the guardians of the target
     */
    event RecoveryProcessSuccessful(
        uint256 indexed recoveryCounter,
        address indexed newController,
        bytes32 indexed newSecretHash,
        address[] guardians
    );

    /**
     * @dev The address of an ERC725 contract where we want to recover
     * and set permissions for a controller address
     */
    function target() external view returns (address);

    /**
     * @dev Returns the current recovery counter
     * When a recovery process is successfully finished the recovery counter is incremented
     */
    function getRecoveryCounter() external view returns (uint256);

    /**
     * @dev Returns the addresses of all guardians
     * The guardians will select an address to be added as a controller
     * key for the linked `target` if he reaches the guardian threshold and
     * provide the correct string that produce the secretHash
     */
    function getGuardians() external view returns (address[] memory);

    /**
     * @dev Returns TRUE if the address provided is a guardian, FALSE otherwise
     * @param _address The address to query
     */
    function isGuardian(address _address) external view returns (bool);

    /**
     * @dev Returns the recovery secret hash
     */
    function getRecoverySecretHash() external view returns (bytes32);

    /**
     * @dev Returns the guardian threshold
     * The guardian threshold represents the minimum number of selection by guardians required
     * for an address to start a recovery process
     */
    function getGuardiansThreshold() external view returns (uint256);

    /**
     * @dev Returns the address of a controller that a `guardian` selected for in order to recover the target
     * @param guardian the address of a guardian to query his selection
     * @return the address that `guardian` selected
     */
    function getGuardianChoice(
        address guardian
    ) external view returns (address);

    /**
     * @dev Adds a guardian of the target
     * @dev Can be called only by the owner
     * @param newGuardian The address to add as a guardian
     */
    function addGuardian(address newGuardian) external;

    /**
     * @dev Removes a guardian of the target
     * @dev Can be called only by the owner
     * @param currentGuardian The address of the existing guardian to remove
     *
     * Requirements:
     *
     * - The guardians count should be higher or equal to the guardain threshold
     */
    function removeGuardian(address currentGuardian) external;

    /**
     * @dev Sets the hash of the secret string to be provided in `recoverOwnership(..)` function
     * @dev Can be called only by the owner
     * @param newRecoverSecretHash The hash of the secret string
     *
     * Requirements:
     *
     * - `secretHash` cannot be bytes32(0)
     */
    function setRecoverySecretHash(bytes32 newRecoverSecretHash) external;

    /**
     * @dev Sets the minimum number of selection by the guardians required so that an
     * address can recover ownership
     *
     * @dev Can be called only by the owner
     * @param guardiansThreshold The threshold to set
     *
     * Requirements:
     * - `guardiansThreshold` cannot be more than the guardians count.
     */
    function setGuardiansThreshold(uint256 guardiansThreshold) external;

    /**
     * @dev select an address to be a potentiel controller address if he reaches
     * the guardian threshold and provide the correct secret string
     *
     * Requirements:
     * - only guardians can select an address
     *
     * @param addressSelected The address selected by the guardian
     */
    function selectNewController(address addressSelected) external;

    /**
     * @dev Recovers the ownership permissions of an address in the linked target
     * and increment the recover counter
     *
     * Requirements
     * - the address of the recoverer must have a selection equal or higher than the threshold
     * defined in `getGuardiansThreshold(...)`
     *
     * - must have provided the right `plainSecret` that produces the secret Hash
     *
     * @param recoverer The address of the recoverer
     * @param plainSecret The secret word that produce the secret Hash
     * @param newHash The new secret Hash to be used in the next recovery process
     */
    function recoverOwnership(
        address recoverer,
        string memory plainSecret,
        bytes32 newHash
    ) external;
}

contracts/LSP11BasicSocialRecovery/LSP11.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.0;

// modules
import {
    OwnableUnset
} from "@erc725/smart-contracts/contracts/custom/OwnableUnset.sol";
import {LSP11BasicSocialRecoveryCore} from "./LSP11BasicSocialRecoveryCore.sol";

/**
 * @title Implementation of LSP11 - Basic Social Recovery standard
 * @dev Sets permission for a controller address after a recovery process to interact with an ERC725
 * contract via the LSP6KeyManager
 */
contract LSP11BasicSocialRecovery is LSP11BasicSocialRecoveryCore {
    /**
     * @notice Sets the target and the owner addresses
     * @param _owner The owner of the LSP11 contract
     * @param target_ The address of the ER725 contract to recover
     */
    constructor(address _owner, address target_) {
        OwnableUnset._setOwner(_owner);
        _target = target_;
    }
}

// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.4;

// interfaces
import {ILSP11BasicSocialRecovery} from "./ILSP11BasicSocialRecovery.sol";

// libraries
import {LSP6Utils} from "../LSP6KeyManager/LSP6Utils.sol";

// modules
import {ERC725} from "@erc725/smart-contracts/contracts/ERC725.sol";
import {
    OwnableUnset
} from "@erc725/smart-contracts/contracts/custom/OwnableUnset.sol";
import {ERC165} from "@openzeppelin/contracts/utils/introspection/ERC165.sol";
import {
    EnumerableSet
} from "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";

// constants
import {ALL_REGULAR_PERMISSIONS} from "../LSP6KeyManager/LSP6Constants.sol";
import {_INTERFACEID_LSP11} from "./LSP11Constants.sol";
import {
    CallerIsNotGuardian,
    GuardianAlreadyExist,
    GuardianDoNotExist,
    GuardiansNumberCannotGoBelowThreshold,
    ThresholdCannotBeHigherThanGuardiansNumber,
    SecretHashCannotBeZero,
    AddressZeroNotAllowed,
    ThresholdNotReachedForRecoverer,
    WrongPlainSecret
} from "./LSP11Errors.sol";

/**
 * @title Core Implementation of LSP11-BasicSocialRecovery standard
 * @dev Sets permission for a controller address after a recovery process to interact with an ERC725
 * contract via the LSP6KeyManager
 */
abstract contract LSP11BasicSocialRecoveryCore is
    OwnableUnset,
    ERC165,
    ILSP11BasicSocialRecovery
{
    using EnumerableSet for EnumerableSet.AddressSet;

    address internal _target;

    // The guardians threshold
    uint256 internal _guardiansThreshold;

    // The number of successfull recovery processes
    uint256 internal _recoveryCounter;

    // The secret hash to be set by the owner
    bytes32 internal _recoverySecretHash;

    // Stores the address selected by a guardian
    // in the current `_recoveryCounter`
    mapping(uint256 => mapping(address => address)) internal _guardiansChoice;

    // List of guardians addresses
    EnumerableSet.AddressSet internal _guardians;

    /**
     * @dev Throws if called by any account other than the guardians
     */
    modifier onlyGuardians() virtual {
        if (!_guardians.contains(msg.sender))
            revert CallerIsNotGuardian(msg.sender);
        _;
    }

    /**
     * @inheritdoc ERC165
     */
    function supportsInterface(
        bytes4 _interfaceId
    ) public view virtual override returns (bool) {
        return
            _interfaceId == _INTERFACEID_LSP11 ||
            super.supportsInterface(_interfaceId);
    }

    /**
     * @inheritdoc ILSP11BasicSocialRecovery
     */
    function target() public view virtual override returns (address) {
        return _target;
    }

    /**
     * @inheritdoc ILSP11BasicSocialRecovery
     */
    function getRecoveryCounter()
        public
        view
        virtual
        override
        returns (uint256)
    {
        return _recoveryCounter;
    }

    /**
     * @inheritdoc ILSP11BasicSocialRecovery
     */
    function getGuardians()
        public
        view
        virtual
        override
        returns (address[] memory)
    {
        return _guardians.values();
    }

    /**
     * @inheritdoc ILSP11BasicSocialRecovery
     */
    function isGuardian(
        address _address
    ) public view virtual override returns (bool) {
        return _guardians.contains(_address);
    }

    /**
     * @inheritdoc ILSP11BasicSocialRecovery
     */
    function getGuardiansThreshold()
        public
        view
        virtual
        override
        returns (uint256)
    {
        return _guardiansThreshold;
    }

    /**
     * @inheritdoc ILSP11BasicSocialRecovery
     */
    function getRecoverySecretHash()
        public
        view
        virtual
        override
        returns (bytes32)
    {
        return _recoverySecretHash;
    }

    /**
     * @inheritdoc ILSP11BasicSocialRecovery
     */
    function getGuardianChoice(
        address guardian
    ) public view virtual override returns (address) {
        return _guardiansChoice[_recoveryCounter][guardian];
    }

    /**
     * @inheritdoc ILSP11BasicSocialRecovery
     */
    function addGuardian(
        address newGuardian
    ) public virtual override onlyOwner {
        if (_guardians.contains(newGuardian))
            revert GuardianAlreadyExist(newGuardian);

        _guardians.add(newGuardian);
        emit GuardianAdded(newGuardian);
    }

    /**
     * @inheritdoc ILSP11BasicSocialRecovery
     */
    function removeGuardian(
        address existingGuardian
    ) public virtual override onlyOwner {
        if (!_guardians.contains(existingGuardian))
            revert GuardianDoNotExist(existingGuardian);
        if (_guardians.length() == _guardiansThreshold)
            revert GuardiansNumberCannotGoBelowThreshold(_guardiansThreshold);

        _guardians.remove(existingGuardian);
        emit GuardianRemoved(existingGuardian);
    }

    /**
     * @inheritdoc ILSP11BasicSocialRecovery
     */
    function setGuardiansThreshold(
        uint256 newThreshold
    ) public virtual override onlyOwner {
        if (newThreshold > _guardians.length())
            revert ThresholdCannotBeHigherThanGuardiansNumber(
                newThreshold,
                _guardians.length()
            );

        _guardiansThreshold = newThreshold;
        emit GuardiansThresholdChanged(newThreshold);
    }

    /**
     * @inheritdoc ILSP11BasicSocialRecovery
     * @dev Throws if hash provided is bytes32(0)
     */
    function setRecoverySecretHash(
        bytes32 newRecoverSecretHash
    ) public virtual override onlyOwner {
        if (newRecoverSecretHash == bytes32(0)) revert SecretHashCannotBeZero();

        _recoverySecretHash = newRecoverSecretHash;
        emit SecretHashChanged(newRecoverSecretHash);
    }

    /**
     * @inheritdoc ILSP11BasicSocialRecovery
     */
    function selectNewController(
        address addressSelected
    ) public virtual override onlyGuardians {
        uint256 currentRecoveryCounter = _recoveryCounter;

        _guardiansChoice[currentRecoveryCounter][msg.sender] = addressSelected;
        emit SelectedNewController(
            currentRecoveryCounter,
            msg.sender,
            addressSelected
        );
    }

    /**
     * @inheritdoc ILSP11BasicSocialRecovery
     */
    function recoverOwnership(
        address recoverer,
        string memory plainSecret,
        bytes32 newSecretHash
    ) public virtual override {
        // caching storage variables
        uint256 currentRecoveryCounter = _recoveryCounter;
        address[] memory guardians = _guardians.values();
        address target_ = _target;

        _validateRequirements(
            recoverer,
            currentRecoveryCounter,
            plainSecret,
            newSecretHash,
            guardians
        );

        _recoveryCounter++;
        _recoverySecretHash = newSecretHash;
        emit SecretHashChanged(newSecretHash);

        address keyManager = ERC725(target_).owner();

        // Setting permissions for `recoverer`
        (bytes32[] memory keys, bytes[] memory values) = LSP6Utils
            .generateNewPermissionsKeys(
                ERC725(target_),
                recoverer,
                ALL_REGULAR_PERMISSIONS
            );

        LSP6Utils.setDataViaKeyManager(keyManager, keys, values);

        emit RecoveryProcessSuccessful(
            currentRecoveryCounter,
            recoverer,
            newSecretHash,
            guardians
        );

        _cleanStorage(currentRecoveryCounter, guardians.length, guardians);
    }

    /**
     * @dev The number of guardians should be reasonable, as the validation method
     * is using a loop to check the selection of each guardian
     *
     * Throws if:
     * - The address trying to recover didn't reach the guardiansThreshold
     * - The new hash being set is bytes32(0)
     * - The secret word provided is incorrect
     */
    function _validateRequirements(
        address recoverer,
        uint256 currentRecoveryCounter,
        string memory plainSecret,
        bytes32 newHash,
        address[] memory guardians
    ) internal view virtual {
        if (recoverer == address(0)) revert AddressZeroNotAllowed();
        uint256 callerSelections;

        unchecked {
            for (uint256 i; i < guardians.length; i++) {
                if (
                    _guardiansChoice[currentRecoveryCounter][guardians[i]] ==
                    recoverer
                ) callerSelections++;
            }
        }

        uint256 guardiansThreshold = _guardiansThreshold;

        if (callerSelections < guardiansThreshold)
            revert ThresholdNotReachedForRecoverer(
                recoverer,
                callerSelections,
                guardiansThreshold
            );
        if (newHash == bytes32(0)) revert SecretHashCannotBeZero();
        if (keccak256(abi.encodePacked(plainSecret)) != _recoverySecretHash)
            revert WrongPlainSecret();
    }

    /**
     * @dev Remove the guardians choice after a successfull recovery process
     * To avoid keeping unnecessary state
     */
    function _cleanStorage(
        uint256 recoveryCounter,
        uint256 guardiansLength,
        address[] memory guardians
    ) internal virtual {
        unchecked {
            for (uint256 i; i < guardiansLength; i++) {
                delete _guardiansChoice[recoveryCounter][guardians[i]];
            }
        }
    }
}

// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.0;

// modules
import {
    LSP11BasicSocialRecoveryInitAbstract
} from "./LSP11BasicSocialRecoveryInitAbstract.sol";

/**
 * @title Deployable Proxy Implementation of LSP11 - Basic Social Recovery standard
 * @dev Sets permission for a controller address after a recovery process to interact with an ERC725
 * contract via the LSP6KeyManager
 */
contract LSP11BasicSocialRecoveryInit is LSP11BasicSocialRecoveryInitAbstract {
    constructor() {
        _disableInitializers();
    }

    /**
     * @notice Sets the target and the owner addresses
     * @param _owner The owner of the LSP11 contract
     * @param target_ The address of the ER725 contract to recover
     */
    function initialize(
        address target_,
        address _owner
    ) public virtual initializer {
        LSP11BasicSocialRecoveryInitAbstract._initialize(target_, _owner);
    }
}

// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.0;

// modules
import {
    Initializable
} from "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import {
    OwnableUnset
} from "@erc725/smart-contracts/contracts/custom/OwnableUnset.sol";
import {LSP11BasicSocialRecoveryCore} from "./LSP11BasicSocialRecoveryCore.sol";

/**
 * @title Inheritable Proxy Implementation of LSP11 - Basic Social Recovery standard
 * @dev Sets permission for a controller address after a recovery process to interact with an ERC725
 * contract via the LSP6KeyManager
 */
contract LSP11BasicSocialRecoveryInitAbstract is
    Initializable,
    LSP11BasicSocialRecoveryCore
{
    function _initialize(
        address _owner,
        address target_
    ) internal virtual onlyInitializing {
        OwnableUnset._setOwner(_owner);
        _target = target_;
    }
}

// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.0;

// --- ERC165 interface ids

bytes4 constant _INTERFACEID_LSP11 = 0x049a28f1;

// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.0;

// --- Errors

/**
 * @dev reverts when the caller is not a guardian
 */
error CallerIsNotGuardian(address caller);

/**
 * @dev reverts when adding an already existing guardian
 */
error GuardianAlreadyExist(address addressToAdd);

/**
 * @dev reverts when removing a non-existing guardian
 */
error GuardianDoNotExist(address addressToRemove);

/**
 * @dev reverts when removing a guardian and the threshold
 * is equal to the number of guardians
 */
error GuardiansNumberCannotGoBelowThreshold(uint256 guardianThreshold);

/**
 * @dev reverts when setting the guardians threshold to a number
 * higher than the guardians number
 */
error ThresholdCannotBeHigherThanGuardiansNumber(
    uint256 thresholdGiven,
    uint256 guardianNumber
);

/**
 * @dev reverts when the secret hash provided is equal to bytes32(0)
 */
error SecretHashCannotBeZero();

/**
 * @dev reverts when `recoverOwnership(..)` is called with a recoverer that didn't reach
 * the guardians threshold
 * @param recoverer The address of the recoverer
 * @param selections The number of selections that the recoverer have
 * @param guardiansThreshold The minimum number of selection needed
 */
error ThresholdNotReachedForRecoverer(
    address recoverer,
    uint256 selections,
    uint256 guardiansThreshold
);

/**
 * @dev reverts when the plain secret produce a different hash than the
 * secret hash originally set
 */
error WrongPlainSecret();

/**
 * @dev reverts when the address zero calls `recoverOwnership(..)` function
 */
error AddressZeroNotAllowed();

contracts/LSP14Ownable2Step/ILSP14Ownabl.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.4;

/**
 * @title Interface of the LSP14 - Ownable 2-step standard, an extension of the [EIP173] (Ownable) standard with 2-step process to transfer or renounce ownership.
 */
interface ILSP14Ownable2Step {
    /**
     * @dev Emitted when {transferOwnership(..)} was called and the first step of transferring ownership completed successfully which leads to {pendingOwner} being updated.
     * @notice The transfer of ownership of the contract was initiated. Pending new owner set to: `newOwner`.
     * @param previousOwner The address of the previous owner.
     * @param newOwner The address of the new owner.
     */
    event OwnershipTransferStarted(
        address indexed previousOwner,
        address indexed newOwner
    );

    /**
     * @inheritdoc OwnableUnset
     * event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
     */

    /**
     * @dev Emitted when starting the {renounceOwnership(..)} 2-step process.
     * @notice Ownership renouncement initiated.
     */
    event RenounceOwnershipStarted();

    /**
     * @dev Emitted when the ownership of the contract has been renounced.
     * @notice Successfully renounced ownership of the contract. This contract is now owned by anyone, it's owner is `address(0)`.
     */
    event OwnershipRenounced();

    /**
     * @inheritdoc OwnableUnset
     * function {owner()} external view returns (address);
     */

    /**
     * @dev The address that ownership of the contract is transferred to.
     * This address may use {acceptOwnership()} to gain ownership of the contract.
     */
    function pendingOwner() external view returns (address);

    /**
     * @dev Initiate the process of transferring ownership of the contract by setting the new owner as the pending owner.
     *
     * If the new owner is a contract that supports + implements LSP1, this will also attempt to notify the new owner that ownership has been transferred to them by calling the {universalReceiver()} function on the `newOwner` contract.
     *
     * @notice Transfer ownership initiated by `newOwner`.
     *
     * @param newOwner The address of the new owner.
     */
    function transferOwnership(address newOwner) external;

    /**
     * @dev Transfer ownership of the contract from the current {owner()} to the {pendingOwner()}.
     *
     * Once this function is called:
     * - The current {owner()} will lose access to the functions restricted to the {owner()} only.
     * - The {pendingOwner()} will gain access to the functions restricted to the {owner()} only.
     *
     * @notice `msg.sender` is accepting ownership of contract: `address(this)`.
     */
    function acceptOwnership() external;

    /**
     * @dev Renounce ownership of the contract in a 2-step process.
     *
     * 1. The first call will initiate the process of renouncing ownership.
     * 2. The second call is used as a confirmation and will leave the contract without an owner.
     *
     * @notice `msg.sender` is renouncing ownership of contract `address(this)`.
     */
    function renounceOwnership() external;
}

