     * - ERC20 {Transfer} event with `address(0)` as the `to` address.
     */
    function _burn(
        address from,
        uint256 amount,
        bytes memory data
    ) internal virtual override {
        emit IERC20.Transfer(from, address(0), amount);
        super._burn(from, amount, data);
    }
