            "setData(bytes32,bytes)",
            bytes32(
                bytes.concat(
                    _LSP1_UNIVERSAL_RECEIVER_DELEGATE_PREFIX,
                    bytes2(0),
                    bytes20(newURDTypeId)
                )
            ),
            bytes.concat(bytes20(newURDAddress))
